Here's a modern MSTest approach using `HttpMessageHandler` mocking, async test methods, and cancellation testing:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailure()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs longer than 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` or `.GetAwaiter()` needed |
| `[Timeout(ms)]` | Guards against hangs; works with async tests in MSTest v3+ |
| `Assert.ThrowsExactlyAsync` | MSTest v3.8+ replacement for `ThrowsExceptionAsync` (exact type match) |
| `CancellationToken` propagation | Verify the token is forwarded by pre-cancelling a `CancellationTokenSource` |
| `HttpMessageHandler` fake | Avoids mocking `HttpClient` directly (which is not designed for mocking) |

> **Note:** `Assert.ThrowsExactlyAsync` requires MSTest 3.8+. On older versions, use `Assert.ThrowsExceptionAsync<T>` instead (it also matches derived types).
